import type { NutritionFacts } from "../../componentTypes/nutritionFacts"
import type { Semantics } from "../semantics"

const nutritionFacts = (semantics: Semantics): NutritionFacts => ({
  borderRadius: semantics.borderRadius.lg,
  cardBorderColor: semantics.color.stroke.muted,
  cardBorderWidth: semantics.borderWidth.sm,
  cardPadding: semantics.spacing.gap.cards.sm,
  cardExplainerContainerBottomMargin: semantics.spacing.spaceSm,
  cardGap: semantics.spacing.spaceXl,
  bodyPadding: semantics.spacing.padding.container.md,
  blockGap: semantics.spacing.gap.cards.md,
})
export default nutritionFacts
